// Post-generation validation and cleanup
let html = $input.first().json.message?.content || $input.first().json.text || '';

// Strip markdown fences if present
html = html.replace(/^```html?\n?/i, '').replace(/\n?```$/i, '').trim();

const brand = $('Prepare Prompt Context').first().json.brand;
const errors = [];
const warnings = [];

// CRITICAL VALIDATIONS

// 1. Check for wrong logo (sentice)
if (html.includes('sentice-author-logo') || html.includes('sentice.com')) {
  errors.push('CRITICAL: Found sentice reference — replacing with PowerPlug assets');
  html = html.replace(/https?:\/\/[^"']*sentice-author-logo[^"']*/gi, brand.logoUrl);
  html = html.replace(/https?:\/\/www\.sentice\.com\/contact/gi, brand.contactUrl);
  html = html.replace(/sentice\.com/gi, 'powerplug.ai');
}

// 2. Verify correct logo is present
if (!html.includes('powerplug-logo')) {
  warnings.push('WARNING: PowerPlug logo not found in author section');
}

// 3. Verify contact URL
if (!html.includes(brand.contactUrl)) {
  warnings.push('WARNING: PowerPlug contact URL not found in CTAs');
}

// 4. Check for JavaScript buttons in TOC/FAQ (should use details/summary)
const jsButtonCount = (html.match(/onclick="var [ab]=this/g) || []).length;
if (jsButtonCount > 1) {
  warnings.push(`WARNING: Found ${jsButtonCount} JS-driven accordions — should use <details>/<summary>`);
}

// 5. Check section count
const sectionCount = (html.match(/id="section\d+"/g) || []).length;
const faqPresent = html.includes('id="faq"');

// 6. Check responsive meta
const hasStyle = html.includes('<style>');
const hasMediaQuery = html.includes('@media');

// 7. Verify brand colors
const hasNavy = html.includes(brand.colors.primaryNavy);
const hasGreen = html.includes(brand.colors.accentGreen);

return [{
  json: {
    html: html,
    validation: {
      passed: errors.length === 0,
      errors,
      warnings,
      stats: {
        sectionCount,
        faqPresent,
        hasStyleBlock: hasStyle,
        hasMediaQueries: hasMediaQuery,
        correctLogo: html.includes('powerplug-logo'),
        correctContact: html.includes(brand.contactUrl),
        usesNavyColor: hasNavy,
        usesGreenAccent: hasGreen,
        charCount: html.length,
        estimatedWordCount: Math.round(html.replace(/<[^>]*>/g, ' ').split(/\s+/).length)
      }
    }
  }
}];

// Load the system prompt from the Improved_N8N_Prompt.txt
// In production, this would be stored in n8n credentials or a connected storage
// For now, it's embedded in the workflow as a static text node output

const brandData = $('Extract Brand Intelligence').first().json;
const contentData = $('Prepare Prompt Context').first().json;

// The system prompt is the full content of Improved_N8N_Prompt.txt
// In production deployment, replace this with a file read or credential reference
const systemPrompt = `You are a senior B2B content strategist and frontend engineer producing enterprise-grade long-form articles for PowerPlug.ai — a PC power management software company serving large enterprises.

BRAND IDENTITY:
- Company: PowerPlug (https://powerplug.ai)
- Logo: ${brandData.brand.logoUrl}
- Contact: ${brandData.brand.contactUrl}
- Colors: Navy ${brandData.brand.colors.primaryNavy}, Green ${brandData.brand.colors.accentGreen}
- Font: ${brandData.brand.fontStack}
- Social: Facebook, Twitter/X, LinkedIn

CRITICAL RULES:
1. Use ONLY the PowerPlug logo URL provided above in the About the Author section
2. ALL CTA buttons link to ${brandData.brand.contactUrl}
3. Use <details>/<summary> for TOC and FAQ — NO JavaScript onclick buttons
4. Inline CSS only (one <style> block allowed for pseudo-elements and @media queries)
5. Direction: LTR, Language: English
6. Never fabricate statistics or link to non-existent pages
7. Floating buttons on LEFT side (site has WhatsApp widget on right)
8. Social hover colors: Facebook=#1877F2, Twitter=#000000, LinkedIn=#0A66C2

OUTPUT: Complete HTML article ready for WordPress paste. No markdown, no explanation.`;

return [{
  json: {
    ...contentData,
    systemPrompt
  }
}];
